css_template:
#{{ID}} .rep-bottom-bar {
    position: absolute;
    bottom: 40px;
    left: 96px;
    width: var(--v-width, 1728px);
    height: 60px;
    background: {{{PRIMARY_BG}}};
    display: flex;
    align-items: center;
    overflow: hidden;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform-origin: left center;
    z-index: 5;
}
#{{ID}} .ticker-track {
    display: flex;
    align-items: center;
    white-space: nowrap;
    padding-left: 100%;
}
#{{ID}} .ticker-item {
    color: {{{TITLE_COLOR}}};
    font-size: {{FONT_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: uppercase;
    padding: 0 20px;
}
#{{ID}} .ticker-sep {
    {{SEPARATOR_CSS}}
}
#{{ID}} .wiper-v8 {
    position: absolute;
    left: 0;
    width: auto;
    min-width: 150px;
    padding: 0 40px;
    height: 100%;
    background: {{{WIPER_BG}}};
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5);
    z-index: 10;
    box-sizing: border-box;
    overflow: hidden;
}
#{{ID}} .wiper-v8-gleam {
    position: absolute;
    top: 0;
    left: -100%;
    width: 60%;
    height: 100%;
    display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
    background: {{{WIPER_GLEAM_BG}}};
    transform: skewX(-20deg);
    pointer-events: none;
    animation: sweep-gleam-v8 {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
#{{ID}} .wiper-text-v8 {
    font-weight: {{WIPER_FONT_WEIGHT}};
    font-size: {{WIPER_FONT_SIZE}}px;
    font-family: {{WIPER_FONT}}, sans-serif;
    color: {{{WIPER_TEXT_COLOR}}};
    letter-spacing: {{WIPER_LETTER_SPACING}}px;
    position: relative;
    z-index: 11;
    white-space: nowrap;
}
@keyframes sweep-gleam-v8 {
    0% { left: -100%; }
    100% { left: 200%; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".rep-bottom-bar");
    const tickerTrack = root.querySelector(".ticker-track");
    const wiper = root.querySelector(".wiper-v8");
    const wiperTextEl = root.querySelector(".wiper-text-v8");
    const dataEl = root.querySelector("#f-news-list");
    if(!container || !dataEl) return;

    const DEFAULT_WIPER = "{{WIPER_TEXT}}";

    let newsList = [];
    try { 
        newsList = JSON.parse(dataEl.innerHTML || "[]"); 
    } catch(e) { 
        newsList = []; 
    }

    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        }

        const catRaw = (newsList.length > 0 && newsList[0].category) ? newsList[0].category : "";
        const labelText = (catRaw || "").trim() || (DEFAULT_WIPER || "").trim();
        if (wiper) {
            wiper.style.display = labelText ? 'flex' : 'none';
            if (wiperTextEl) wiperTextEl.innerText = labelText;
        }

        if (tickerTrack) {
            tl.add(() => {
                const trackWidth = tickerTrack.scrollWidth || 0;
                const speedPxPerSec = (parseFloat("{{speed}}") || parseFloat("{{TICKER_SPEED}}") || 50);
                if (speedPxPerSec > 0 && trackWidth > 0) {
                    const duration = trackWidth / speedPxPerSec;
                    gsap.to(tickerTrack, {
                        x: -trackWidth,
                        duration: duration,
                        ease: 'none',
                        repeat: -1
                    });
                }
            });
        }
        return tl;
    };
    root.__slt_hide = () => {
        gsap.killTweensOf(tickerTrack);
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        if (textTl) {
            const sync = {{{TEXT_ANIM_OUT_SYNC}}};
            if (sync) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
})();
